rus_pops = [p for p in data.keys() if "Russian" in p]
ukr_pops = [p for p in data.keys() if "Ukrainian" in p]

print(f"{'Russian Pop':<25} | {'Ukrainian Pop':<25} | {'Distance':<10}")
print("-" * 65)

distances = []

for ru in rus_pops:
    for ua in ukr_pops:
        dist = euclidean_distance(data[ru], data[ua])
        distances.append((dist, ru, ua))

# Sort by distance
distances.sort()

# Print top 10 closest
print("TOP 10 CLOSEST PAIRS:")
for d, r, u in distances[:10]:
    print(f"{r:<25} | {u:<25} | {d:.4f}")

print("\nTOP 10 FURTHEST PAIRS:")
for d, r, u in distances[-10:]:
    print(f"{r:<25} | {u:<25} | {d:.4f}")

# Calculate Average Distance
avg_dist = sum(d for d, r, u in distances) / len(distances)
print(f"\nAverage Distance across all {len(distances)} pairs: {avg_dist:.4f}")

